import os
import torch
import torch.nn as nn
import torch.nn.functional as F

os.environ['TRANSFORMERS_OFFLINE'] = '1'
os.environ['HF_HUB_OFFLINE'] = '1'
os.environ['HF_DATASETS_OFFLINE'] = '1'

import timm
from transformers import AutoModel


class GradReverse(torch.autograd.Function):
    @staticmethod
    def forward(ctx, x, lambda_):
        ctx.lambda_ = lambda_
        return x.view_as(x)

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output.neg() * ctx.lambda_, None


def grad_reverse(x, lambda_):
    return GradReverse.apply(x, lambda_)


class FocalLoss(nn.Module):
    def __init__(self, alpha=None, gamma=2.0, reduction='mean'):
        super().__init__()
        self.alpha = alpha
        self.gamma = gamma
        self.reduction = reduction

    def forward(self, inputs, targets):
        ce_loss = F.cross_entropy(inputs, targets, weight=self.alpha, reduction='none')
        pt = torch.exp(-ce_loss)
        focal_loss = ((1 - pt) ** self.gamma) * ce_loss
        if self.reduction == 'mean':
            return focal_loss.mean()
        elif self.reduction == 'sum':
            return focal_loss.sum()
        return focal_loss


class WildlifeCLIP(nn.Module):
    def __init__(self, num_classes=10, dropout=0.3):
        super().__init__()
        self.backbone = timm.create_model(
            'vit_base_patch16_clip_224.openai',
            pretrained=True,
            num_classes=0
        )
        self.dropout = nn.Dropout(dropout)
        self.classifier = nn.Linear(768, num_classes)

    def forward(self, x):
        features = self.backbone(x)
        features = self.dropout(features)
        return self.classifier(features)


class WildlifeCLIP_DANN(nn.Module):
    def __init__(self, num_classes=10, num_domains=3, dropout=0.3, domain_dim=128):
        super().__init__()
        self.backbone = timm.create_model(
            'vit_base_patch16_clip_224.openai',
            pretrained=True,
            num_classes=0
        )
        self.dropout = nn.Dropout(dropout)
        self.classifier = nn.Linear(768, num_classes)
        self.domain_classifier = nn.Sequential(
            nn.Linear(768, domain_dim),
            nn.ReLU(),
            nn.Dropout(0.2),
            nn.Linear(domain_dim, num_domains)
        )

    def forward(self, x, lambda_=0.0):
        features = self.backbone(x)
        rev_features = grad_reverse(features, lambda_)
        dom_logits = self.domain_classifier(rev_features)
        features = self.dropout(features)
        class_logits = self.classifier(features)
        return class_logits, dom_logits


class WildlifeResNet(nn.Module):
    def __init__(self, num_classes=10, pretrained=True):
        super().__init__()
        import torchvision.models as models
        self.backbone = models.resnet50(weights='IMAGENET1K_V2' if pretrained else None)
        in_features = self.backbone.fc.in_features
        self.backbone.fc = nn.Identity()
        self.classifier = nn.Linear(in_features, num_classes)

    def forward(self, x):
        features = self.backbone(x)
        return self.classifier(features)


class WildlifeDINOv2(nn.Module):
    def __init__(self, num_classes=10, dropout=0.3):
        super().__init__()
        self.backbone = AutoModel.from_pretrained('facebook/dinov2-base', local_files_only=True)
        self.dropout = nn.Dropout(dropout)
        self.classifier = nn.Linear(768, num_classes)

    def forward(self, x):
        out = self.backbone(x)
        features = out.last_hidden_state[:, 0, :]  # CLS token
        features = self.dropout(features)
        return self.classifier(features)


class WildlifeDINOv2_DANN(nn.Module):
    def __init__(self, num_classes=10, num_domains=3, dropout=0.3, domain_dim=128):
        super().__init__()
        self.backbone = AutoModel.from_pretrained('facebook/dinov2-base', local_files_only=True)
        self.dropout = nn.Dropout(dropout)
        self.classifier = nn.Linear(768, num_classes)
        self.domain_classifier = nn.Sequential(
            nn.Linear(768, domain_dim),
            nn.ReLU(),
            nn.Dropout(0.2),
            nn.Linear(domain_dim, num_domains)
        )

    def forward(self, x, lambda_=0.0):
        out = self.backbone(x)
        features = out.last_hidden_state[:, 0, :]
        rev_features = grad_reverse(features, lambda_)
        dom_logits = self.domain_classifier(rev_features)
        features = self.dropout(features)
        class_logits = self.classifier(features)
        return class_logits, dom_logits


def get_model(backbone='clip_vitb16', num_classes=10, pretrained=True, use_dann=False, dropout=0.3, num_domains=3):
    if backbone == 'resnet50':
        return WildlifeResNet(num_classes=num_classes, pretrained=pretrained)
    elif backbone == 'clip_vitb16':
        if use_dann:
            return WildlifeCLIP_DANN(num_classes=num_classes, num_domains=num_domains, dropout=dropout)
        else:
            return WildlifeCLIP(num_classes=num_classes, dropout=dropout)
    elif backbone == 'dinov2_base':
        if use_dann:
            return WildlifeDINOv2_DANN(num_classes=num_classes, num_domains=num_domains, dropout=dropout)
        else:
            return WildlifeDINOv2(num_classes=num_classes, dropout=dropout)
    else:
        raise ValueError(f'Unsupported backbone: {backbone}')
